proof_block:
// Re-reveal the opaque spec fns locally (idempotent) so each conjunct of the
// post-conditions becomes visible to z3 before we start chaining facts.
reveal(HostState::next_get_request_preconditions);
reveal(HostState::next_get_request_postconditions);
reveal(HostState::host_state_common_postconditions);
reveal(HostState::host_state_common_preconditions);
reveal(HostState::host_state_packet_preconditions);
reveal(HostState::abstractable);
reveal(HostState::valid);

// From the requires we already know pre_self_ has a received packet, and
// from the preconditions we know that packet is a GetRequest. Binding cp
// lets us refer to the same cpacket on both sides without making z3 unify
// two distinct `match` instantiations.
assert(pre_self_.received_packet is Some);
let cp = pre_self_.received_packet.unwrap();
assert(cp.msg is Message);
assert(cp.msg.arrow_Message_m() is GetRequest);

// Local shorthand for the abstracted send-set on each side; this is what
// `next_get_request` is parameterised on.
let out1: Set<Packet> = abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@);
let out2: Set<Packet> = abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@);

if (post1_self_.next_get_request_postconditions(pre_self_, r1@))
    && (post2_self_.next_get_request_postconditions(pre_self_, r2@))
{
    // ---- Pull the high-level transition facts into scope for *both* runs. ----
    // The match on pre_self_.received_packet inside next_get_request_postconditions
    // forces these to fire with the same cpacket cp on both sides.
    assert(next_get_request(pre_self_@, post1_self_@, cp@, out1));
    assert(next_get_request(pre_self_@, post2_self_@, cp@, out2));

    // ---- Fields next_get_request pins to pre@. ----
    // (These are direct conjuncts of next_get_request.)
    assert(post1_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post2_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post1_self_@.h == pre_self_@.h);
    assert(post2_self_@.h == pre_self_@.h);
    assert(post1_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post2_self_@.num_delegations == pre_self_@.num_delegations);

    // ---- Fields host_state_common_postconditions pins to pre. ----
    // self.constants == pre.constants is on the (concrete) HostState; lift it
    // to the abstract view via HostState::view's body.
    assert(post1_self_.constants == pre_self_.constants);
    assert(post2_self_.constants == pre_self_.constants);
    assert(post1_self_@.constants == pre_self_@.constants);
    assert(post2_self_@.constants == pre_self_@.constants);

    // ---- next_get_request_postconditions' final clause clears received_packet. ----
    assert(post1_self_.received_packet is None);
    assert(post2_self_.received_packet is None);
    assert(post1_self_@.received_packet is None);
    assert(post2_self_@.received_packet is None);

    // ---- Extract the existential witnesses from next_get_request on each side. ----
    // next_get_request's last conjunct is
    //   exists |sm,m,b| next_get_request_reply(pre@, post@, cp@.src,
    //       cp@.msg.arrow_Message_seqno(), cp@.msg.arrow_Message_m().arrow_GetRequest_key(),
    //       sm, m, out, b)
    // We choose witnesses on each side so we can talk about the resulting post.sd
    // and post.received_requests directly.
    let src  = cp@.src;
    let seq  = cp@.msg.arrow_Message_seqno();
    let key  = cp@.msg.arrow_Message_m().arrow_GetRequest_key();

    let w1 = choose |sm: SingleMessage<Message>, m: Message, b: bool|
        next_get_request_reply(pre_self_@, post1_self_@, src, seq, key, sm, m, out1, b);
    let w2 = choose |sm: SingleMessage<Message>, m: Message, b: bool|
        next_get_request_reply(pre_self_@, post2_self_@, src, seq, key, sm, m, out2, b);

    assert(next_get_request_reply(pre_self_@, post1_self_@, src, seq, key, w1.0, w1.1, out1, w1.2));
    assert(next_get_request_reply(pre_self_@, post2_self_@, src, seq, key, w2.0, w2.1, out2, w2.2));

    // ---- Pointwise equality on the two AbstractHostState views. ----
    // Combining the asserts above, every field of post1_self_@ that is pinned
    // (constants, delegation_map, h, num_delegations, received_packet) matches
    // the corresponding field of post2_self_@.
    assert(post1_self_@.constants == post2_self_@.constants);
    assert(post1_self_@.delegation_map == post2_self_@.delegation_map);
    assert(post1_self_@.h == post2_self_@.h);
    assert(post1_self_@.num_delegations == post2_self_@.num_delegations);
    assert(post1_self_@.received_packet == post2_self_@.received_packet);
}
